import pytest
import requests

BASE_URL = "http://hr-app/api"
KNOWN_BENEFIT_ID = "<KNOWN_BENEFIT_ID>"

@pytest.fixture
def employee_headers():
    token = <get_employee_token>()
    return {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

def test_forbidden_role_returns_403(employee_headers):
    resp = requests.get(f"{BASE_URL}/benefits/{KNOWN_BENEFIT_ID}", headers=employee_headers)
    assert resp.status_code == 403
    body = resp.json()
    assert "error" in body or "message" in body
